#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int h[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &h[i]);
        }
        int left = 0, right = N - 1;
        int reservoirs = 0;
        while (left <= right) {
            if (h[left] < h[right]) {
                int max = h[right];
                while (right >= 0 && h[right] <= max) {
                    right--;
                }
                reservoirs++;
            } else {
                int max = h[left];
                while (left < N && h[left] <= max) {
                    left++;
                }
                reservoirs++;
            }
        }
        printf("%d\n", reservoirs);
    }
    return 0;
}

