                if (h[left] < h[right]) {
                    int max = h[right];
                    while (right >= 0 && h[right] <= max) {
                        right--;
                    }
                    reservoirs++;
                } else {
                    int max = h[left];
                    while (left < N && h[left] <= max) {
                        left++;
                    }
